    override fun load() {
        super.load()
        Log.d(TAG, "Plugin loading - initializing MWDAT SDK")

        try {
            Wearables.initialize(context)
            sdkInitialized = true
            Log.d(TAG, "SDK initialized successfully")
            observeRegistrationState()
            observeDevices()
        } catch (e: Exception) {
            sdkInitialized = false
            Log.e(TAG, "SDK initialize failed: ${e.message}")
