    @PluginMethod
    fun stopSession(call: PluginCall) {
        try {
            streamSession?.close()
            Log.d(TAG, "Stream session closed")
        } catch (e: Exception) {
            Log.e(TAG, "stopSession error: ${e.message}")
        }

        streamSession = null
        isStreaming = false
        latestFrameBytes = null
        latestFrameTimestamp = 0
