    private fun byteBufferToArray(buffer: ByteBuffer): ByteArray {
        val buf = buffer.duplicate()
        buf.rewind()
        val bytes = ByteArray(buf.remaining())
        buf.get(bytes)
        return bytes
    }

    private fun compressFrameBytes(bytes: ByteArray, quality: Int, maxWidth: Int): JSObject {
        val result = JSObject()

        try {
            // First try decoding as JPEG/PNG (capturePhoto path)
            var bitmap = BitmapFactory.decodeByteArray(bytes, 0, bytes.size)

            // If null, treat as raw NV21 YUV frame from video stream
            if (bitmap == null) {
                // NV21: size = width * height * 1.5
                // MEDIUM quality = 896x504, 677376 bytes
                // HIGH quality = 1920x1080 would be 3110400
                // LOW quality = 640x360 would be 345600
                val frameSize = bytes.size
                var frameW = latestFrameWidth; var frameH = latestFrameHeight
                if (frameW == 0 || frameH == 0) { frameW = 504; frameH = 896 }
                Log.d(TAG, "Raw YUV frame: ${bytes.size} bytes -> ${frameW}x${frameH}")
                try {
                    // Convert I420 (planar YUV) -> NV21 (semi-planar)
                    // I420: [Y plane][U plane][V plane]
                    // NV21: [Y plane][V0 U0 V1 U1 ...]
                    val ySize = frameW * frameH
                    val uvSize = ySize / 4
                    val nv21 = ByteArray(bytes.size)
                    // Copy Y plane as-is
                    System.arraycopy(bytes, 0, nv21, 0, ySize)
                    // Interleave V and U
                    val uOffset = ySize
                    val vOffset = ySize + uvSize
                    for (i in 0 until uvSize) {
                        nv21[ySize + i * 2] = bytes[vOffset + i]     // V first (NV21)
                        nv21[ySize + i * 2 + 1] = bytes[uOffset + i] // then U
                    }
                    val yuvImage = android.graphics.YuvImage(nv21, android.graphics.ImageFormat.NV21, frameW, frameH, null)
                    val jpegStream = ByteArrayOutputStream()
                    yuvImage.compressToJpeg(android.graphics.Rect(0, 0, frameW, frameH), quality, jpegStream)
                    val jpegBytes2 = jpegStream.toByteArray()
                    bitmap = BitmapFactory.decodeByteArray(jpegBytes2, 0, jpegBytes2.size)
                } catch (yuvError: Exception) {
                    Log.e(TAG, "YUV conversion failed: ${yuvError.message}")
                }
            }

            if (bitmap == null) {
                result.put("base64", "")
                result.put("width", 0)
                result.put("height", 0)
                result.put("timestamp", 0)
                result.put("byteSize", 0)
                return result
            }

            if (bitmap.width > maxWidth) {
                val scale = maxWidth.toFloat() / bitmap.width.toFloat()
                val newHeight = (bitmap.height * scale).toInt()
                bitmap = Bitmap.createScaledBitmap(bitmap, maxWidth, newHeight, true)
            }

            val stream = ByteArrayOutputStream()
            bitmap.compress(Bitmap.CompressFormat.JPEG, quality, stream)
            val jpegBytes = stream.toByteArray()
            val base64 = Base64.encodeToString(jpegBytes, Base64.NO_WRAP)

            result.put("base64", base64)
            result.put("width", bitmap.width)
            result.put("height", bitmap.height)
            result.put("timestamp", System.currentTimeMillis())
            result.put("byteSize", jpegBytes.size)

        } catch (e: Exception) {
            Log.e(TAG, "Frame compression failed: ${e.message}")
            result.put("base64", "")
            result.put("width", 0)
            result.put("height", 0)
            result.put("timestamp", 0)
            result.put("byteSize", 0)
        }

        return result
