    override fun handleOnDestroy() {
        super.handleOnDestroy()
        pluginScope.cancel()

        try {
            streamSession?.close()
        } catch (e: Exception) {
            Log.e(TAG, "Cleanup close error: ${e.message}")
        }

        streamSession = null
        isStreaming = false
        latestFrameBytes = null
        Log.d(TAG, "Plugin destroyed, resources cleaned up")
    }
